export class ActivityComponent{constructor(containerId){this.container=document.getElementById(containerId);}render(activities){if(!this.container)return;this.container.innerHTML=activities.map(activity=>`<div class="activity-item"><div class="activity-icon ${activity.type}"><span class="material-symbols-outlined">${activity.icon}</span></div><div class="activity-content"><div class="activity-title">${activity.title}</div><div class="activity-time">${activity.time}</div></div></div>`).join('');}addActivity(activity){if(!this.container)return;const item=document.createElement('div');item.className='activity-item';item.innerHTML=`<div class="activity-icon ${activity.type}"><span class="material-symbols-outlined">${activity.icon}</span></div><div class="activity-content"><div class="activity-title">${activity.title}</div><div class="activity-time">${activity.time}</div></div>`;item.style.opacity='0';item.style.transform='translateY(-10px)';this.container.insertBefore(item,this.container.firstChild);requestAnimationFrame(()=>{item.style.transition='opacity 0.3s,transform 0.3s';item.style.opacity='1';item.style.transform='translateY(0)';});}removeActivity(index){const item=this.container.children[index];if(item){item.style.opacity='0';item.style.transform='translateX(-10px)';setTimeout(()=>item.remove(),300);}}clear(){if(this.container){this.container.innerHTML='';}}}export default ActivityComponent;